async (params, browser) => {
  // Open PubMed search
  await browser.open(`https://pubmed.ncbi.nlm.nih.gov/?term=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.results-article, article, .search-results', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract papers
  const results = await browser.evaluate(`const results = []; document.querySelectorAll('article.full-docsum, .results-article').forEach((el, i) => { if (i < 15) { const titleEl = el.querySelector('a.docsum-title, .title a'); const authEl = el.querySelector('.docsum-authors, .authors'); const journalEl = el.querySelector('.docsum-journal-citation, .journal'); const pmidEl = el.querySelector('.docsum-pmid, .pmid'); results.push({ title: titleEl?.textContent?.trim() || '', url: titleEl?.href || '', authors: authEl?.textContent?.trim() || '', journal: journalEl?.textContent?.trim() || '', pmid: pmidEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return results
}
